    // More simply, since a >= 1, b^3 < n, so b < cuberoot(n).
    // Since a <= b, the maximum value for b is floor(cbrt(n)).

    // Max value for b
    const maxB = Math.floor(Math.pow(n, 1/3));

    // We iterate over possible values of a and b such that 1 <= a <= b and a^3 + b^3 <= n.

