        // Determine the maximum value for b for the current a.
        // b^3 <= n - a^3
        const maxBForA = Math.floor(Math.pow(n - a3, 1/3));

        // b must be at least a
        const startB = a;

        for (let b = startB; b <= maxBForA; b++) {
