    // Since a^3 + b^3 <= n and 1 <= a <= b, we have 2*a^3 <= n, so a <= cuberoot(n/2).
    // And a^3 + a^3 <= n, so 2*a^3 <= n.
    // More simply, since a >= 1, b^3 < n, so b < cuberoot(n).
    // Since a <= b, the maximum value for b is floor(cbrt(n)).

    // Max value for b
    const maxB = Math.floor(Math.pow(n, 1/3));

    // We iterate over possible values of a and b such that 1 <= a <= b and a^3 + b^3 <= n.

    for (let a = 1; ; a++) {
        const a3 = a * a * a;

        // If the smallest possible sum (a^3 + a^3) already exceeds n, we can stop.
        if (2 * a3 > n) {
            break;
        }

        // Determine the maximum value for b for the current a.
        // b^3 <= n - a^3
        const maxBForA = Math.floor(Math.pow(n - a3, 1/3));

        // b must be at least a
        const startB = a;

        for (let b = startB; b <= maxBForA; b++) {
            const b3 = b * b * b;
            const sum = a3 + b3;

            if (sum <= n) {
                // Store the sum and count the ways it's formed.
                // We use a Map to store the sum -> count (number of distinct pairs found so far).
                // Since we iterate a <= b, each pair (a, b) is unique and meets the criteria.
                sums.set(sum, (sums.get(sum) || 0) + 1);
            }
        }
    }

    const goodNumbers = [];

    // Collect all sums that have appeared at least twice.
    for (const [sum, count] of sums.entries()) {
